+async function generateGoogleVideoViaRest(params: {
+  baseUrl: string;
+  headers: Record<string, string>;
+  deadline: ReturnType<typeof createProviderOperationDeadline>;
+  model: string;
+  prompt: string;
+  durationSeconds?: number;
+  aspectRatio?: "16:9" | "9:16";
